"""Load eval results from JSONL and align two systems by task id.

Accepted per-row score fields (first present wins): 'score', 'correct', 'pass', 'passed',
'reward', 'value'. Booleans and 0/1 ints become 0.0/1.0; floats pass through.
Task id field (first present): 'task_id', 'id', 'task', 'example_id', 'qid'.
"""
from __future__ import annotations

import json
from pathlib import Path

_SCORE_FIELDS = ("score", "correct", "pass", "passed", "reward", "value", "accuracy")
_ID_FIELDS = ("task_id", "id", "task", "example_id", "qid", "question_id")


def _coerce(v) -> float:
    if isinstance(v, bool):
        return 1.0 if v else 0.0
    return float(v)


def _pick(row: dict, fields, kind: str):
    for f in fields:
        if f in row:
            return row[f]
    raise KeyError(f"no {kind} field found in row (looked for {fields}): {row}")


def load_scores(path, score_field: str | None = None, id_field: str | None = None) -> dict:
    """Read a JSONL file -> {task_id: score}. Raises on duplicate ids."""
    out: dict = {}
    p = Path(path)
    with p.open(encoding="utf-8") as fh:
        for ln, line in enumerate(fh, 1):
            line = line.strip()
            if not line:
                continue
            row = json.loads(line)
            tid = row[id_field] if id_field else _pick(row, _ID_FIELDS, "task-id")
            raw = row[score_field] if score_field else _pick(row, _SCORE_FIELDS, "score")
            if tid in out:
                raise ValueError(f"{p}: duplicate task id {tid!r} (line {ln})")
            out[str(tid)] = _coerce(raw)
    if not out:
        raise ValueError(f"{p}: no rows loaded")
    return out


def align(baseline: dict, candidate: dict):
    """Inner-join two {task_id: score} dicts on shared ids.

    Returns (baseline_scores, candidate_scores, info) where info reports the overlap and any
    dropped task ids so callers can warn about mismatched sets.
    """
    shared = sorted(set(baseline) & set(candidate))
    info = {
        "n_shared": len(shared),
        "n_baseline_only": len(set(baseline) - set(candidate)),
        "n_candidate_only": len(set(candidate) - set(baseline)),
    }
    if not shared:
        raise ValueError("no shared task ids between baseline and candidate")
    b = [baseline[t] for t in shared]
    c = [candidate[t] for t in shared]
    return b, c, info


def load_paired(path, baseline_field: str = "baseline", candidate_field: str = "candidate",
                id_field: str | None = None):
    """Read a single JSONL where each row has BOTH systems' scores.

    Returns (baseline_scores, candidate_scores) aligned by row order.
    """
    base, cand = [], []
    p = Path(path)
    with p.open(encoding="utf-8") as fh:
        for line in fh:
            line = line.strip()
            if not line:
                continue
            row = json.loads(line)
            base.append(_coerce(row[baseline_field]))
            cand.append(_coerce(row[candidate_field]))
    if not base:
        raise ValueError(f"{p}: no rows loaded")
    return base, cand
